{
  "cmd": "powershell -Command \"Get-CimInstance Win32_Process | Where-Object { $_.Name -match 'brave.exe|chrome.exe|msedge.exe' -and $_.CommandLine -match 'youtube' } | ForEach-Object { Stop-Process -Id $_.ProcessId -Force }  & 'C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe' --new-window https://www.youtube.com'",
  "msg": "Toggling YouTube window..."
}

{
  "cmd": "powershell -Command \"Get-CimInstance Win32_Process | Where-Object { $_.Name -match 'brave.exe|chrome.exe|msedge.exe' -and $_.CommandLine -match 'youtube' } | ForEach-Object { Stop-Process -Id $_.ProcessId -Force } \" & \"C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe\" --new-window \"https://www.youtube.com\"",
  "msg": "Attempting to launch a new instance of YouTube in Chrome..."
}

{
  "message": "Error on the terminal",
  "terminaloutput": "",
  "terminalerror": "Command failed: powershell -Command \"Get-CimInstance Win32_Process | Where-Object { $_.Name -match 'brave.exe|chrome.exe|msedge.exe' -and $_.CommandLine -match 'youtube' } | ForEach-Object { Stop-Process -Id $_.ProcessId -Force } \" & \"C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe\" --new-window \"https://www.youtube.com\"\nThe system cannot find the path specified.\r\n",
  "cmdRunByAi": "powershell -Command \"Get-CimInstance Win32_Process | Where-Object { $_.Name -match 'brave.exe|chrome.exe|msedge.exe' -and $_.CommandLine -match 'youtube' } | ForEach-Object { Stop-Process -Id $_.ProcessId -Force } \" & \"C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe\" --new-window \"https://www.youtube.com\""
}

{
  "cmd": "powershell -Command \"Get-CimInstance -ClassName Win32_Process -Filter \"CommandLine likes '*youtube*'\"); Get-Process -Name Chrome -ErrorAction SilentlyContinue | ForEach-Object { Stop-Process -Id $_.Id -Force }\"",
  "msg": "Removing any existing YouTube window..."
}

{
  "cmd": "powershell -Command \"Get-Process -Name Chrome -ErrorAction SilentlyContinue | Where-Object { $_.MainWindowTitle -like '*YouTube*' } | ForEach-Object { Stop-Process -Id $_.Id -Force }\"",
  "msg": "Removing any existing YouTube window..."
}

{
  "message": "Error on the terminal",
  "terminaloutput": "",
  "terminalerror": "Command failed: powershell -Command \"Get-Process -Name Chrome -ErrorAction SilentlyContinue | Where-Object { $_.MainWindowTitle -like '*YouTube*' } | ForEach-Object { Stop-Process -Id $_.Id -Force }\"\n",
  "cmdRunByAi": "powershell -Command \"Get-Process -Name Chrome -ErrorAction SilentlyContinue | Where-Object { $_.MainWindowTitle -like '*YouTube*' } | ForEach-Object { Stop-Process -Id $_.Id -Force }\""
}

{
  "cmd": "powershell -Command \"& 'C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe' --new-window \"https://www.youtube.com\"",
  "msg": "Launching a new instance of Chrome with YouTube opened..."
}

{
  "cmd": "powershell -Command \"start chrome https://www.youtube.com\"",
  "msg": "Launching a new instance of Chrome with YouTube opened..."
}

{
  "cmd": "start \"C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe\" https://www.youtube.com",
  "msg": "Launching a new instance of Chrome with YouTube opened..."
}
